mapper.select:
SELECT rsv.id, rsv.reader_id AS readerId, r.name AS readerName, r.reader_no AS readerNo, rsv.book_id AS bookId, b.title AS bookTitle, b.book_code AS bookCode, b.author AS author, rsv.reservation_date AS reservationDate, rsv.expire_date AS expireDate, rsv.status, rsv.create_time AS createTime FROM library_reservation rsv LEFT JOIN library_reader r ON rsv.reader_id = r.id LEFT JOIN library_book b ON rsv.book_id = b.id
AND rsv.reader_id = #{query.readerId}
AND rsv.book_id = #{query.bookId}
AND rsv.status = #{query.status}
ORDER BY rsv.id DESC
